<section class="admin-page-head"><div><p class="eyebrow">FACTURĂ</p><h1><?= e($invoice['number']?:'#'.$invoice['id']) ?></h1><p>Comanda <?= e($invoice['order_number']?:'—') ?> · <?= e($invoice['email']?:'—') ?></p></div><div class="button-row"><?php if($invoice['document_hash']): ?><a class="admin-button" target="_blank" href="<?= e(url('/factura/'.$invoice['document_hash'])) ?>">Deschide PDF ↗</a><?php endif; ?><a class="admin-button secondary" href="<?= e(url('/admin/facturi/'.$invoice['id'].'/ubl')) ?>">Descarcă RO e-Factura XML/UBL</a></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="admin-two-columns"><div><section class="admin-panel"><h2>Document</h2><dl class="admin-details"><dt>Status</dt><dd><?= e($invoice['status']) ?></dd><dt>Data emiterii</dt><dd><?= e($invoice['issue_date']?:'—') ?></dd><dt>Scadență</dt><dd><?= e($invoice['due_date']?:'—') ?></dd><dt>Tip client</dt><dd><?= e($invoice['customer_type']) ?></dd><dt>Hash document</dt><dd class="hash-value"><?= e($invoice['document_hash']?:'—') ?></dd></dl></section><section class="admin-panel"><h2>Poziții</h2><?php foreach($items as $item): ?><div class="admin-order-item"><div><strong><?= e($item['name']) ?></strong><small><?= e($item['sku']) ?> · <?= e($item['quantity']) ?></small></div><b><?= money($item['total_minor']) ?></b></div><?php endforeach; ?><div class="admin-order-total"><span>Total</span><strong><?= money($invoice['grand_total_minor']) ?></strong></div></section></div><aside><section class="admin-panel"><h2>Jurnal imuabil</h2><ol class="admin-timeline"><?php foreach($events as $event): ?><li><strong><?= e($event['event_type']) ?></strong><span><?= e($event['status']?:'') ?></span><time><?= date('d.m.Y H:i',strtotime($event['created_at'])) ?></time></li><?php endforeach; ?></ol></section></aside></div>
